parameters.query:
CREATE TABLE IF NOT EXISTS cv_sessions (
  session_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id VARCHAR NOT NULL,
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW(),
  session_state VARCHAR DEFAULT 'INIT',
  current_cv_id UUID REFERENCES cvs(id),
  collected_data JSONB DEFAULT '{}',
  message_history JSONB DEFAULT '[]',
  last_message_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_cv_sessions_user_id ON cv_sessions(user_id);
CREATE UNIQUE INDEX IF NOT EXISTS idx_cv_sessions_user_unique ON cv_sessions(user_id) WHERE session_state != 'DONE';

