parameters.jsCode:
// CERVEAU — Détection intention + préparation contexte
const telegramMsg = $('INPUT').first().json;
const userId = String(telegramMsg.message.chat.id);
const firstName = telegramMsg.message.chat.first_name || 'utilisateur';
const rawText = (telegramMsg.message.text || '').trim();

// Session existante (peut être vide si première fois)
const sessionRows = $input.all();
const existingSession = sessionRows.length > 0 && sessionRows[0].json.session_id
  ? sessionRows[0].json
  : null;

const sessionState = existingSession ? existingSession.session_state : 'INIT';
const collectedData = existingSession ? (existingSession.collected_data || {}) : {};
const messageHistory = existingSession ? (existingSession.message_history || []) : [];
const sessionId = existingSession ? existingSession.session_id : null;
const currentCvId = existingSession ? existingSession.current_cv_id : null;
const nbTurns = existingSession ? (existingSession.nb_turns || 0) : 0;

// Détection de commande
const commandMatch = rawText.match(/^\/([a-zA-Z]+)(?:\s+(.+))?$/);
const command = commandMatch ? commandMatch[1].toLowerCase() : null;
const commandArg = commandMatch ? (commandMatch[2] || null) : null;

// Déterminer la route
let route = 'conversation';
if (command === 'start' || command === 'nouveau') route = 'nouveau';
else if (command === 'liste') route = 'liste';
else if (command === 'modifier') route = 'modifier';
else if (command === 'adapter') route = 'adapter';
else if (command === 'lettre') route = 'lettre';
else if (command === 'envoyer') route = 'envoyer';
else if (command === 'apercu') route = 'apercu';
else if (command === 'supprimer') route = 'supprimer';
else if (command === 'help' || command === 'aide') route = 'aide';

return [{
  json: {
    userId,
    firstName,
    rawText,
    command,
    commandArg,
    route,
    sessionId,
    sessionState,
    collectedData,
    messageHistory,
    currentCvId,
    nbTurns
  }
}];

const cvRows = $input.all();
const userId = $('CERVEAU').first().json.userId;

if (!cvRows || cvRows.length === 0 || !cvRows[0].json.id) {
  return [{ json: { responseText: '📭 Tu n\'as pas encore de CV enregistré.\n\nTape /nouveau pour créer ton premier CV !' } }];
}

const lines = cvRows.map((row, i) => {
  const cv = row.json;
  return `${i+1}. *${cv.target_role || 'Sans titre'}* — ${cv.target_sector || '?'} (${cv.date}) ${cv.pdf_status}`;
});

const text = `📋 *Tes CV (${cvRows.length})*\n\n${lines.join('\n')}\n\nUtilise /apercu [numéro] pour voir un CV.`;
return [{ json: { responseText: text } }];

