parameters.jsCode:
const cvRows = $input.all();
if (!cvRows || cvRows.length === 0 || !cvRows[0].json.id) {
  return [{ json: { responseText: 'Tu n\'as pas encore de CV.\n\nTape /nouveau pour créer ton premier CV !' } }];
}
const lines = cvRows.map((row, i) => {
  const cv = row.json;
  return `${i+1}. *${cv.target_role || 'Sans titre'}* - ${cv.target_sector || '?'} (${cv.date}) [${cv.status}]`;
});
const text = `*Tes CV (${cvRows.length})*\n\n${lines.join('\n')}\n\nUtilise /apercu [id] pour voir un CV.`;
return [{ json: { responseText: text } }];

