      {
        "id": "cva-session-loader",
        "name": "SESSION_LOADER",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          550,
          300
        ],
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "parameters": {
          "operation": "executeQuery",
          "query": "=SELECT s.session_id, s.session_state, s.current_cv_id, s.collected_data, s.message_history, s.nb_turns\nFROM cv_sessions s\nWHERE s.user_id = '{{ $json.message.chat.id }}'\nORDER BY s.last_message_at DESC\nLIMIT 1;"
        },
        "alwaysOutputData": true,
        "retryOnFail": true
      },
      {
        "id": "cva-cerveau",
        "name": "CERVEAU",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          850,
          300
        ],
        "parameters": {
          "mode": "runOnceForAllItems",
          "jsCode": "const telegramMsg = $('INPUT').first().json;\nconst userId = String(telegramMsg.message.chat.id);\nconst firstName = telegramMsg.message.chat.first_name || 'utilisateur';\nconst rawText = (telegramMsg.message.text || '').trim();\n\nconst sessionRows = $input.all();\nconst existingSession = sessionRows.length > 0 && sessionRows[0].json.session_id\n  ? sessionRows[0].json\n  : null;\n\nconst sessionState = existingSession ? existingSession.session_state : 'INIT';\nconst collectedData = existingSession ? (existingSession.collected_data || {}) : {};\nconst messageHistory = existingSession ? (existingSession.message_history || []) : [];\nconst sessionId = existingSession ? existingSession.session_id : null;\nconst currentCvId = existingSession ? existingSession.current_cv_id : null;\nconst nbTurns = existingSession ? (existingSession.nb_turns || 0) : 0;\n\nconst commandMatch = rawText.match(/^\\/([a-zA-Z]+)(?:\\s+(.+))?$/);\nconst command = commandMatch ? commandMatch[1].toLowerCase() : null;\nconst commandArg = commandMatch ? (commandMatch[2] || null) : null;\n\nlet route = 'conversation';\nif (command === 'start' || command === 'nouveau') route = 'nouveau';\nelse if (command === 'liste') route = 'liste';\nelse if (command === 'modifier') route = 'modifier';\nelse if (command === 'adapter') route = 'adapter';\nelse if (command === 'lettre') route = 'lettre';\nelse if (command === 'envoyer') route = 'envoyer';\nelse if (command === 'apercu') route = 'apercu';\nelse if (command === 'supprimer') route = 'supprimer';\nelse if (command === 'help' || command === 'aide') route = 'aide';\n\nreturn [{ json: { userId, firstName, rawText, command, commandArg, route, sessionId, sessionState, collectedData, messageHistory, currentCvId, nbTurns } }];"
        }
      },
      {
        "id": "cva-router",
        "name": "ROUTER",
        "type": "n8n-nodes-base.switch",
        "typeVersion": 3.4,
        "position": [
          1150,
          300
        ],
        "parameters": {
          "mode": "rules",
          "rules": {
            "values": [
              {
                "conditions": {
                  "options": {
                    "caseSensitive": false,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "conditions": [
                    {
                      "leftValue": "={{ $json.route }}",
                      "rightValue": "nouveau",
                      "operator": {
                        "type": "string",
                        "operation": "equals"
                      }
                    }
                  ]
                },
                "outputIndex": 0
              },
              {
                "conditions": {
                  "options": {
                    "caseSensitive": false,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "conditions": [
                    {
                      "leftValue": "={{ $json.route }}",
                      "rightValue": "liste",
                      "operator": {
                        "type": "string",
                        "operation": "equals"
                      }
                    }
                  ]
                },
                "outputIndex": 1
              }
            ]
          },
          "fallbackOutput": 2
        }
      },
      {
        "id": "cva-reset-session",
        "name": "RESET_SESSION",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          1450,
          120
        ],
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "parameters": {
          "resource": "database",
          "operation": "executeQuery",
          "query": "=INSERT INTO cv_sessions (user_id, session_state, collected_data, message_history, nb_turns, last_message_at)\nVALUES ('{{ $json.userId }}', 'COLLECTING', '{}', '[]', 0, NOW())\nON CONFLICT (user_id)\nDO UPDATE SET session_state = 'COLLECTING', collected_data = '{}', message_history = '[]', nb_turns = 0, current_cv_id = NULL, last_message_at = NOW(), updated_at = NOW()\nRETURNING session_id, session_state"
        },
        "retryOnFail": true
      },
      {
        "id": "cva-list-cvs",
        "name": "LIST_CVS",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          1450,
          300
        ],
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "parameters": {
          "operation": "executeQuery",
          "query": "=SELECT id, target_role, target_sector, created_at::date AS date,\n  CASE WHEN pdf_url IS NOT NULL THEN 'OK' ELSE 'draft' END AS status\nFROM cvs WHERE user_id = '{{ $('CERVEAU').first().json.userId }}'\nORDER BY created_at DESC LIMIT 10;"
        },
        "alwaysOutputData": true,
        "retryOnFail": true
      },
      {
        "id": "cva-agent",
        "name": "AGENT_CLAUDE",
        "type": "@n8n/n8n-nodes-langchain.agent",
        "typeVersion": 3.1,
        "position": [
          1750,
          300
        ],
        "parameters": {
          "promptType": "define",
          "text": "={{ $json.rawText || $('CERVEAU').first().json.rawText }}",
          "options": {
            "systemMessage": "=Tu es CV Architect, expert en CV professionnels via Telegram.\n\nCONTEXTE:\n- User: {{ $('CERVEAU').first().json.firstName }} ({{ $('CERVEAU').first().json.userId }})\n- Etat: {{ $('CERVEAU').first().json.sessionState }}\n- Tour: {{ $('CERVEAU').first().json.nbTurns }}\n- Donnees: {{ JSON.stringify($('CERVEAU').first().json.collectedData) }}\n\nHISTORIQUE:\n{{ $('CERVEAU').first().json.messageHistory.slice(-6).map(m => m.role + ': ' + m.content).join('\\n') }}\n\nREGLES:\n- INIT/nouveau: accueille, presente-toi, pose Bloc1 (poste, niveau, pays). Max 3 questions.\n- COLLECTING: collecte par blocs (1-Identite, 2-Experiences, 3-Formation, 4-Competences, 5-Extras, 6-Style). Max 3 questions par message. Relance si vague. A 80% propose recapitulatif.\n- REVIEWING: montre le JSON CV structure entre ```json et ```. Demande confirmation.\n- READY: propose /modifier /adapter /lettre /envoyer\n\nABSOLU: N'invente jamais. Reponses max 300 chars. Francais sauf si anglais recu.",
            "maxIterations": 5,
            "timeout": 60000
          }
        }
      },
      {
        "id": "cva-lm",
        "name": "LM_GPT4O",
        "type": "@n8n/n8n-nodes-langchain.lmChatOpenAi",
        "typeVersion": 1.3,
        "position": [
          1750,
          500
        ],
        "credentials": {
          "openAiApi": {
            "id": "0zCm2AMTb5pDX8Sa",
            "name": "OpenAi account"
          }
        },
        "parameters": {
          "model": {
            "__rl": true,
            "mode": "list",
            "value": "gpt-4o-mini"
          },
          "options": {
            "temperature": 0.7,
            "maxTokens": 1000
          }
        }
      },
      {
        "id": "cva-format-list",
        "name": "FORMAT_LIST",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          1750,
          120
        ],
        "parameters": {
          "jsCode": "const cvRows = $input.all();\nif (!cvRows || cvRows.length === 0 || !cvRows[0].json.id) {\n  return [{ json: { responseText: 'Tu n\\'as pas encore de CV.\\n\\nTape /nouveau pour créer ton premier CV !' } }];\n}\nconst lines = cvRows.map((row, i) => {\n  const cv = row.json;\n  return `${i+1}. *${cv.target_role || 'Sans titre'}* - ${cv.target_sector || '?'} (${cv.date}) [${cv.status}]`;\n});\nconst text = `*Tes CV (${cvRows.length})*\\n\\n${lines.join('\\n')}\\n\\nUtilise /apercu [id] pour voir un CV.`;\nreturn [{ json: { responseText: text } }];"
        }
      },
