          "query": "=INSERT INTO cv_sessions (user_id, session_state, message_history, nb_turns, last_message_at)\nVALUES ('{{ $('CERVEAU').first().json.userId }}', 'COLLECTING', '[]'::jsonb, 1, NOW())\nON CONFLICT (user_id)\nDO UPDATE SET nb_turns = cv_sessions.nb_turns + 1, session_state = CASE WHEN cv_sessions.session_state = 'INIT' THEN 'COLLECTING' ELSE cv_sessions.session_state END, last_message_at = NOW(), updated_at = NOW()\nRETURNING session_id"
        },
