const sessionState = existingSession ? existingSession.session_state : 'INIT';
const collectedData = existingSession ? (existingSession.collected_data || {}) : {};
const messageHistory = existingSession ? (existingSession.message_history || []) : [];
const sessionId = existingSession ? existingSession.session_id : null;
const currentCvId = existingSession ? existingSession.current_cv_id : null;
const nbTurns = existingSession ? (existingSession.nb_turns || 0) : 0;

const commandMatch = rawText.match(/^\/([a-zA-Z]+)(?:\s+(.+))?$/);
const command = commandMatch ? commandMatch[1].toLowerCase() : null;
