parameters.jsCode:
const telegramMsg = $('INPUT').first().json;
const userId = String(telegramMsg.message.chat.id);
const firstName = telegramMsg.message.chat.first_name || 'utilisateur';
const rawText = (telegramMsg.message.text || '').trim();

const sessionRows = $input.all();
const existingSession = sessionRows.length > 0 && sessionRows[0].json.session_id ? sessionRows[0].json : null;

const sessionState = existingSession ? existingSession.session_state : 'INIT';
const collectedData = existingSession ? (existingSession.collected_data || {}) : {};
const messageHistory = existingSession ? (existingSession.message_history || []) : [];
const sessionId = existingSession ? existingSession.session_id : null;
const currentCvId = existingSession ? existingSession.current_cv_id : null;
const nbTurns = existingSession ? (existingSession.nb_turns || 0) : 0;

const commandMatch = rawText.match(/^\/([a-zA-Z]+)(?:\s+(.+))?$/);
const command = commandMatch ? commandMatch[1].toLowerCase() : null;
const commandArg = commandMatch ? (commandMatch[2] || null) : null;

let route = 'conversation';
if (command === 'start' || command === 'nouveau') route = 'nouveau';
else if (command === 'liste') route = 'liste';

const historyText = Array.isArray(messageHistory)
  ? messageHistory.slice(-6).map(m => m.role + ': ' + m.content).join('\n')
  : '';

return [{ json: { userId, firstName, rawText, command, commandArg, route, sessionId, sessionState, collectedData, messageHistory, currentCvId, nbTurns, historyText } }];

const cvRows = $input.all();
if (!cvRows || cvRows.length === 0 || !cvRows[0].json.id) {
  return [{ json: { responseText: 'Pas encore de CV.\n\nTape /nouveau pour creer ton premier CV !' } }];
}
const lines = cvRows.map((row, i) => {
  const cv = row.json;
  return String(i+1) + '. *' + String(cv.target_role || 'Sans titre') + '* - ' + String(cv.date || '?') + ' [' + String(cv.status) + ']';
});
return [{ json: { responseText: '*Tes CV (' + String(cvRows.length) + ')*\n\n' + lines.join('\n') } }];

